594	
595	    async fn classify_distractions(
596	        &self,
597	        request: Request<DistractionRequest>,
598	    ) -> Result<Response<DistractionList>, Status> {
599	        let req = request.into_inner();
600	        let url = req.url;
601	
602	        // Extract CSS class/id hints from DOM elements for distraction pattern matching
603	        let css_hints = req
604	            .dom
605	            .as_ref()
606	            .map(|dom| {
607	                dom.elements
608	                    .iter()
609	                    .flat_map(|el| {
610	                        el.attributes
611	                            .iter()
612	                            .filter(|(k, _)| *k == "class" || *k == "id")
613	                            .map(|(_, v)| v.clone())
614	                    })
615	                    .collect::<Vec<_>>()
616	                    .join(" ")
617	            })
618	            .unwrap_or_default();
619	
620	        // Extract all visible text from the distilled DOM for content scanning
621	        let dom_text = req
622	            .dom
623	            .as_ref()
624	            .map(|dom| {
625	                dom.elements
626	                    .iter()
627	                    .map(|el| el.text.as_str())
628	                    .collect::<Vec<_>>()
629	                    .join(" ")
630	            })
631	            .unwrap_or_default();
632	
633	        self.metrics.inc_immune_scans();
634	        let classifier = ans_immune::DistractionClassifier;
635	        let flags = classifier.classify(&url, &dom_text, &css_hints);
636	
637	        let distractions: Vec<_> = flags
638	            .iter()
639	            .map(ans_immune::serialization::distraction_to_proto_list_item)
640	            .collect();
641	
642	        Ok(Response::new(DistractionList {
643	            distractions,
644	            classification_time_us: 0,
645	        }))
646	    }
