648	    async fn scan_injections(
649	        &self,
650	        request: Request<InjectionScanRequest>,
651	    ) -> Result<Response<InjectionScanResult>, Status> {
652	        let req = request.into_inner();
653	
654	        self.metrics.inc_immune_scans();
655	        let detector = ans_immune::InjectionDetector;
656	        let start = std::time::Instant::now();
657	        let result = detector.scan(&req.url, &req.page_content);
658	        let scan_time_us = start.elapsed().as_micros() as i64;
659	
660	        let mut proto = ans_immune::serialization::injection_result_to_proto(&result);
661	        proto.scan_time_us = scan_time_us;
662	
663	        Ok(Response::new(proto))
664	    }
