666	    async fn check_action(
667	        &self,
668	        request: Request<ActionCheckRequest>,
669	    ) -> Result<Response<ActionCheckResponse>, Status> {
670	        let req = request.into_inner();
671	        let session_id = parse_uuid(&req.session_id, "session_id")?;
672	
673	        // Get current URL for context
674	        let url = self.sessions.get_url(session_id).await.unwrap_or_default();
675	
676	        // Build scannable text from the action itself
677	        let action = req.action.as_ref();
678	        let action_text = action.map_or(String::new(), |a| {
679	            format!("{} {} {}", a.action_type, a.selector, a.value)
680	        });
681	
682	        // Run both immune checks
683	        self.metrics.inc_immune_scans();
684	        let classifier = ans_immune::DistractionClassifier;
685	        let distractions = classifier.classify(&url, &action_text, &action_text);
686	
687	        let detector = ans_immune::InjectionDetector;
688	        let injection = detector.scan(&url, &action_text);
689	
690	        let response =
691	            ans_immune::serialization::build_action_check_response(&distractions, &injection);
692	
693	        Ok(Response::new(response))
