129	// ── Heuristic decomposition ──────────────────────────────────────────
130	
131	/// Action verbs mapped to their typical pre-requisites and verification steps.
132	const NAVIGATION_VERBS: &[&str] = &[
133	    "go to", "navigate", "visit", "open", "browse", "find", "search",
134	];
135	
136	const INPUT_VERBS: &[&str] = &[
137	    "fill", "type", "enter", "input", "write", "set", "select", "choose", "pick", "check", "click",
138	    "submit",
139	];
140	
141	const EXTRACTION_VERBS: &[&str] = &[
142	    "read", "extract", "get", "fetch", "download", "scrape", "collect", "copy", "export", "save",
143	];
144	
145	fn decompose_heuristic(description: &str) -> Vec<SubGoal> {
146	    let lower = description.to_lowercase();
147	    let has_navigation = NAVIGATION_VERBS.iter().any(|v| lower.contains(v));
148	    let has_input = INPUT_VERBS.iter().any(|v| lower.contains(v));
149	    let has_extraction = EXTRACTION_VERBS.iter().any(|v| lower.contains(v));
150	
151	    let mut sub_goals = Vec::with_capacity(3);
152	    #[allow(clippy::useless_let_if_seq)]
153	    let mut prev_id: Option<Uuid> = None;
154	
155	    // 1. Navigation phase
156	    if has_navigation {
157	        let id = Uuid::new_v4();
158	        sub_goals.push(SubGoal {
159	            id,
160	            description: format!("Navigate to the target page for: {description}"),
161	            success_criteria: vec!["Page loaded successfully".into()],
162	            depends_on: vec![],
163	            status: SubGoalStatus::Active,
164	        });
165	        prev_id = Some(id);
166	    }
167	
168	    // 2. Interaction phase
169	    if has_input {
170	        let id = Uuid::new_v4();
171	        let deps: Vec<Uuid> = prev_id.into_iter().collect();
172	        sub_goals.push(SubGoal {
173	            id,
174	            description: format!("Interact with the page to complete: {description}"),
175	            success_criteria: vec!["All required fields populated".into()],
176	            depends_on: deps,
177	            status: SubGoalStatus::Pending,
178	        });
179	        prev_id = Some(id);
180	    }
181	
182	    // 3. Verification / extraction phase
183	    if has_extraction || !sub_goals.is_empty() {
184	        let id = Uuid::new_v4();
185	        let deps: Vec<Uuid> = prev_id.into_iter().collect();
186	        sub_goals.push(SubGoal {
187	            id,
188	            description: format!("Verify result for: {description}"),
189	            success_criteria: vec!["Expected outcome confirmed".into()],
190	            depends_on: deps,
191	            status: SubGoalStatus::Pending,
192	        });
193	    }
194	
195	    // Fallback — single sub-goal for unrecognized descriptions
196	    if sub_goals.is_empty() {
197	        sub_goals.push(SubGoal {
198	            id: Uuid::new_v4(),
199	            description: format!("Complete: {description}"),
200	            success_criteria: vec!["Task completed successfully".into()],
201	            depends_on: vec![],
202	            status: SubGoalStatus::Active,
203	        });
204	    }
205	
206	    sub_goals
207	}
