217	mod tests {
218	    use super::*;
219	    use ans_core::goal::GoalContext;
220	
221	    fn make_goal(id: Uuid, desc: &str) -> GoalState {
222	        GoalState {
223	            goal_id: id,
224	            description: desc.into(),
225	            status: GoalStatus::Active,
226	            progress: 0.0,
227	            sub_goals: vec![],
228	            context: GoalContext {
229	                current_url: None,
230	                last_action: None,
231	                last_observation: None,
232	                intent_embedding: vec![],
233	                distraction_count: 0,
234	            },
235	            created_at: chrono::Utc::now(),
236	            updated_at: chrono::Utc::now(),
237	        }
238	    }
239	
240	    #[test]
241	    fn test_insert_and_get() {
242	        let store = GoalStateStore::new(8);
243	        let id = Uuid::new_v4();
244	        let goal = make_goal(id, "Find flights to NYC");
245	
246	        store.insert(goal).unwrap();
247	        let retrieved = store.get(&id).unwrap();
248	        assert_eq!(retrieved.description, "Find flights to NYC");
249	    }
250	
251	    #[test]
252	    fn test_update_progress_triggers_notification() {
253	        let store = GoalStateStore::new(8);
254	        let id = Uuid::new_v4();
255	        store.insert(make_goal(id, "Test goal")).unwrap();
256	
257	        let mut rx = store.subscribe();
258	        store.update_progress(id, 0.5, GoalStatus::Active).unwrap();
259	
260	        let notification = rx.try_recv().unwrap();
261	        assert_eq!(notification.goal_id, id);
262	        assert!((notification.progress - 0.5).abs() < 0.01);
263	    }
