265	    #[test]
266	    fn test_duplicate_insert_fails() {
267	        let store = GoalStateStore::new(8);
268	        let id = Uuid::new_v4();
269	        store.insert(make_goal(id, "First")).unwrap();
270	        assert!(store.insert(make_goal(id, "Second")).is_err());
271	    }
