273	    #[test]
274	    fn test_remove() {
275	        let store = GoalStateStore::new(8);
276	        let id = Uuid::new_v4();
277	        store.insert(make_goal(id, "Test")).unwrap();
278	        assert!(store.get(&id).is_some());
279	        store.remove(&id);
280	        assert!(store.get(&id).is_none());
281	    }
