283	    #[test]
284	    fn test_completed_on_full_progress() {
285	        let store = GoalStateStore::new(8);
286	        let id = Uuid::new_v4();
287	        store.insert(make_goal(id, "Test")).unwrap();
288	
289	        let updated = store.update_progress(id, 1.0, GoalStatus::Active).unwrap();
290	        assert_eq!(updated.status, GoalStatus::Completed);
291	    }
