/// Locate a Chromium/Chrome executable on the system.
///
/// Search order:
/// 1. Playwright cache (`%LOCALAPPDATA%\ms-playwright\` on Windows,
///    `~/Library/Caches/ms-playwright/` on macOS,
///    `~/.cache/ms-playwright/` on Linux)
/// 2. PATH
/// 3. Common install directories (OS-specific)
///
/// On Windows, the `CHROMIUM_OVERRIDE` env var is checked first for a
/// user-supplied executable path.
fn find_chromium() -> Result<PathBuf, LaunchError> {
    // 0. CHROMIUM_OVERRIDE env var (escape hatch for users)
    if let Ok(override_path) = std::env::var("CHROMIUM_OVERRIDE") {
        let pb = PathBuf::from(&override_path);
        if pb.is_file() {
            tracing::info!(path = %pb.display(), "Using CHROMIUM_OVERRIDE");
            return Ok(pb);
        }
        tracing::warn!(path = %override_path, "CHROMIUM_OVERRIDE set but file not found");
    }

    let exe_names: &[&str] = if cfg!(target_os = "windows") {
        &["chrome.exe"]
    } else {
        &["chrome", "Chromium", "chromium"]
    };

    // 1. Playwright cache (highest priority — Playwright-managed Chromium)
    if let Some(pw_chromium) = find_playwright_chromium(exe_names) {
        return Ok(pw_chromium);
    }

    // 2. Search PATH (system chrome/chromium)
    if let Ok(path_var) = std::env::var("PATH") {
        for dir in std::env::split_paths(&path_var) {
            for name in exe_names {
                let candidate = dir.join(name);
                if candidate.is_file() {
                    tracing::debug!(path = %candidate.display(), "Found Chromium on PATH");
                    return Ok(candidate);
                }
            }
        }
    }

    // 3. macOS: check Application bundles
    #[cfg(target_os = "macos")]
    {
        let mac_paths = [
            "/Applications/Chromium.app/Contents/MacOS/Chromium",
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        ];
        for p in &mac_paths {
            let pb = PathBuf::from(p);
            if pb.is_file() {
                return Ok(pb);
            }
        }
    }

    // 4. Windows: check common install directories
    #[cfg(target_os = "windows")]
    {
        let locals = [
            std::env::var("LOCALAPPDATA"),
            std::env::var("ProgramFiles"),
            std::env::var("ProgramFiles(x86)"),
        ];
        for local_var in locals.iter().flatten() {
            let candidates = [
                PathBuf::from(local_var).join("Chromium\\Application\\chrome.exe"),
                PathBuf::from(local_var).join("Google\\Chrome\\Application\\chrome.exe"),
            ];
            for p in &candidates {
                if p.is_file() {
                    tracing::debug!(path = %p.display(), "Found Chromium via install path");
                    return Ok(p.clone());
                }
            }
        }
    }

    Err(LaunchError::ChromiumNotFound {
        message: format!(
            "Chromium executable not found. Install Playwright (recommended): \
             `npm install playwright` then `npx playwright install chromium`, \
             or set CHROMIUM_OVERRIDE env var to a Chrome/Chromium executable path."
        ),
    })
}

/// Search the Playwright browser cache for a Chromium executable.
///
/// Playwright downloads Chromium to a well-known cache directory.
/// The directory name includes a build revision (e.g. `chromium-1155`).
/// We pick the most recent revision found.
fn find_playwright_chromium(exe_names: &[&str]) -> Option<PathBuf> {
    let cache_root = playwright_cache_root()?;

    let chromium_dir = cache_root.read_dir().ok()?.filter_map(|entry| {
        let entry = entry.ok()?;
        let name = entry.file_name();
        let name_s = name.to_string_lossy();
        if name_s.starts_with("chromium-") || name_s.starts_with("chrome-") {
            Some(entry.path())
        } else {
            None
        }
    })
    // Sort descending to pick newest revision
    .max_by(|a, b| {
        let a_name = a.file_name().unwrap_or_default().to_string_lossy();
        let b_name = b.file_name().unwrap_or_default().to_string_lossy();
        alphanum_cmp(&a_name, &b_name)
    })?;

    // Platform-specific executable relative path from the revision dir
    let exe_subpath: &str = if cfg!(target_os = "windows") {
        "chrome-win\\chrome.exe"
    } else if cfg!(target_os = "macos") {
        "chrome-mac/Chromium.app/Contents/MacOS/Chromium"
    } else {
        "chrome-linux/chrome"
    };

    let candidate = chromium_dir.join(exe_subpath);
    if candidate.is_file() {
        tracing::info!(path = %candidate.display(), "Found Chromium in Playwright cache");
        Some(candidate)
    } else {
        // Try with flat filename
        for name in exe_names {
            let flat = chromium_dir.join(name);
            if flat.is_file() {
                tracing::info!(path = %flat.display(), "Found Chromium in Playwright cache (flat)");
                return Some(flat);
            }
        }
        None
    }
}

/// Return the platform-specific Playwright browser cache root.
fn playwright_cache_root() -> Option<PathBuf> {
    #[cfg(target_os = "windows")]
    {
        let local_app_data = std::env::var("LOCALAPPDATA").ok()?;
        Some(PathBuf::from(local_app_data).join("ms-playwright"))
    }
    #[cfg(target_os = "macos")]
    {
        let home = std::env::var("HOME").ok()?;
        Some(PathBuf::from(home).join("Library/Caches/ms-playwright"))
    }
    #[cfg(target_os = "linux")]
    {
        let home = std::env::var("HOME")
            .or_else(|_| std::env::var("XDG_CACHE_HOME"))
            .ok()?;
        let base = if std::env::var("XDG_CACHE_HOME").is_ok() {
            PathBuf::from(home).join("ms-playwright")
        } else {
            PathBuf::from(home).join(".cache/ms-playwright")
        };
        Some(base)
    }
    #[cfg(not(any(target_os = "windows", target_os = "macos", target_os = "linux")))]
    {
        None
    }
}

/// Simple alphanumeric comparison for sorting revision directory names
/// so `chromium-1155` sorts after `chromium-1050`.
fn alphanum_cmp(a: &str, b: &str) -> std::cmp::Ordering {
    let a_parts: Vec<&str> = a.split(|c: char| !c.is_ascii_alphanumeric()).collect();
    let b_parts: Vec<&str> = b.split(|c: char| !c.is_ascii_alphanumeric()).collect();

    for (ap, bp) in a_parts.iter().zip(b_parts.iter()) {
        if let (Ok(an), Ok(bn)) = (ap.parse::<u64>(), bp.parse::<u64>()) {
            match an.cmp(&bn) {
                std::cmp::Ordering::Equal => continue,
                other => return other,
            }
        }
        match ap.cmp(bp) {
            std::cmp::Ordering::Equal => continue,
            other => return other,
        }
    }
    a_parts.len().cmp(&b_parts.len())
}

