/// Replace all sub-goals for an existing goal. Used when the Python
/// LLM decomposer produces richer sub-goals than the heuristic.
pub fn update_sub_goals(
    &self,
    goal_id: Uuid,
    sub_goals: Vec<ans_core::goal::SubGoal>,
) -> Result<GoalState, GoalStoreError> {
    let mut map = self
        .inner
        .write()
        .map_err(|_| GoalStoreError::LockPoisoned)?;
    let state = map
        .get_mut(&goal_id)
        .ok_or(GoalStoreError::NotFound(goal_id))?;

    // Recompute progress from new sub-goals
    let total = sub_goals.len() as f32;
    let done = sub_goals
        .iter()
        .filter(|s| s.status == ans_core::goal::SubGoalStatus::Done)
        .count() as f32;
    let progress = if total > 0.0 { done / total } else { 0.0 };

    state.sub_goals = sub_goals;
    state.progress = progress;
    state.updated_at = chrono::Utc::now();

    if progress >= 1.0 {
        state.status = ans_core::goal::GoalStatus::Completed;
    }

    let snapshot = state.clone();

    let _ = self.tx.send(GoalStateNotification {
        goal_id,
        progress: state.progress,
        status: state.status,
        message: format!("Sub-goals updated: {} total, {:.0}% complete", total, progress * 100.0),
    });

    tracing::info!(%goal_id, sub_goal_count = total, "Goal sub-goals updated from decomposer");
    Ok(snapshot)
}
