async def _execute_action(self, planned: PlannedAction) -> dict:
    """Execute a planned action via gRPC, normalizing action types."""
    sid = self._browser_session_id

    # Normalize action types that the proto doesn't support natively
    action_type = planned.action_type

    # Terminal actions -- handled in _execute_sub_goal, never reach gRPC
    if action_type in ("done", "escalate"):
        return {"message": f"Terminal action: {action_type}"}

    # Semantic aliases
    if action_type == "fill":
        action_type = "fill"  # now valid in ActionType enum

    if action_type == "navigate" and planned.value:
        return await self._grpc.navigate(sid, planned.value)

    return await self._grpc.execute_action(
        sid,
        action_type=action_type,
        selector=planned.selector,
        value=planned.value,
    )
```

